import React from 'react'; // Добавьте этот импорт

interface ActivityCardProps {
  activity: {
    title: string;
    date: string;
  };
}

export default function ActivityCard({ activity }: ActivityCardProps) {
  return (
    <div>
      <h3>{activity.title}</h3>
      <p>{activity.date}</p>
    </div>
  );
}
